function processSheetData() {
  // Open the spreadsheet by its ID
  var spreadsheet = SpreadsheetApp.getActiveSpreadsheet();

  // Select the source sheet
  var sourceSheet = spreadsheet.getSheetByName("SourceSheet");

  // Select the destination sheet
  var destinationSheet = spreadsheet.getSheetByName("DestinationSheet");

  // Get all the data from the source sheet
  var sourceData = sourceSheet.getDataRange().getValues();

  // Process the data (example: convert all text to uppercase)
  var processedData = sourceData.map(function(row) {
